import type { ErpReportChartConfig } from '@linm-soft-org/linm-web-common-components';

/** Extended chart prefs (showCharts in common-components ≥ next publish; optional until then). */
export type ErpReportChartConfigExt = ErpReportChartConfig & {
  showCharts?: boolean;
};

export function isReportChartsEnabled(chart: ErpReportChartConfigExt): boolean {
  return chart.showCharts !== false;
}

export function isReportChartConfigChanged(
  prev: ErpReportChartConfigExt,
  next: ErpReportChartConfigExt,
): boolean {
  return (
    isReportChartsEnabled(prev) !== isReportChartsEnabled(next)
    || prev.showKpiStrip !== next.showKpiStrip
    || prev.defaultChartId !== next.defaultChartId
    || JSON.stringify(prev.enabledChartIds) !== JSON.stringify(next.enabledChartIds)
  );
}
