import React, { useEffect, useLayoutEffect, useRef, useState } from 'react';
import { createPortal } from 'react-dom';
import type { ErpListRowEditHintState } from '@linm-soft-org/linm-web-common-components';
import { setRowEditHintDismissed } from '../../utils/erpListRowEditHintDismiss';
import styles from './ReportGridRowHintLayer.module.css';

export type ReportGridRowHintLayerProps = {
  hint: ErpListRowEditHintState | null;
  onDismiss: () => void;
  /** When set — show "Tôi đã hiểu" and persist dismiss in localStorage. */
  dismissStorageKey?: string;
  understandLabel?: string;
};

const VIEWPORT_MARGIN = 8;
const DEFAULT_UNDERSTAND_LABEL = 'Tôi đã hiểu';

function clampPosition(x: number, y: number, width: number, height: number) {
  const vw = window.innerWidth;
  const vh = window.innerHeight;
  let left = x + 12;
  let top = y + 12;
  if (left + width > vw - VIEWPORT_MARGIN) left = Math.max(VIEWPORT_MARGIN, x - width - 12);
  if (top + height > vh - VIEWPORT_MARGIN) top = Math.max(VIEWPORT_MARGIN, y - height - 12);
  return { left, top };
}

/** Parity `ErpListRowEditHintLayer` — dismiss checkbox until common-components publish. */
export function ReportGridRowHintLayer({
  hint,
  onDismiss,
  dismissStorageKey,
  understandLabel = DEFAULT_UNDERSTAND_LABEL,
}: ReportGridRowHintLayerProps): React.ReactElement | null {
  const ref = useRef<HTMLDivElement | null>(null);
  const [pos, setPos] = useState<{ left: number; top: number } | null>(null);

  useLayoutEffect(() => {
    if (!hint) {
      setPos(null);
      return;
    }
    if (!ref.current) return;
    const rect = ref.current.getBoundingClientRect();
    setPos(clampPosition(hint.x, hint.y, rect.width, rect.height));
  }, [hint]);

  useEffect(() => {
    if (!hint || dismissStorageKey) return;
    const t = window.setTimeout(onDismiss, 8000);
    return () => window.clearTimeout(t);
  }, [hint, dismissStorageKey, onDismiss]);

  const handleUnderstandChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!e.target.checked || !dismissStorageKey) return;
    setRowEditHintDismissed(dismissStorageKey);
    onDismiss();
  };

  if (!hint) return null;

  const style: React.CSSProperties = pos
    ? { left: pos.left, top: pos.top }
    : { left: hint.x + 12, top: hint.y + 12, visibility: 'hidden' };

  return createPortal(
    <div
      ref={ref}
      className={styles.rowEditHint}
      style={style}
      role="status"
      onClick={e => e.stopPropagation()}
    >
      <div className={styles.rowEditHintBody}>
        <i className="fas fa-info-circle" aria-hidden />
        <span>{hint.message}</span>
      </div>
      {dismissStorageKey ? (
        <label className={styles.rowEditHintUnderstand}>
          <input
            type="checkbox"
            data-testid="row-edit-hint-understand"
            onChange={handleUnderstandChange}
          />
          <span>{understandLabel}</span>
        </label>
      ) : null}
    </div>,
    document.body,
  );
}
