import * as XLSX from 'xlsx';
import type { LedgerEntryDto } from '../../services/kt/models';
import { formatDateLocal, formatVnd } from '../../utils/formatters';

export function exportLedgerRowsToExcel(
  rows: LedgerEntryDto[],
  fileName: string,
  headers: {
    date: string;
    account?: string;
    voucher: string;
    counterAccount?: string;
    description: string;
    debit: string;
    credit: string;
    balance?: string;
    balanceDebit?: string;
    balanceCredit?: string;
  },
): void {
  const useSplitBalance = Boolean(headers.balanceDebit || headers.balanceCredit);
  const data = rows.map(r => {
    const row: Record<string, string | number> = {
      [headers.date]: formatDateLocal(r.entryDate),
      [headers.voucher]: r.voucherCode,
    };
    if (headers.counterAccount) {
      row[headers.counterAccount] = r.counterAccountCode?.trim() ?? '';
    }
    row[headers.description] = r.description ?? '';
    row[headers.debit] = r.debitAmount;
    row[headers.credit] = r.creditAmount;
    if (useSplitBalance) {
      row[headers.balanceDebit ?? 'Dư Nợ'] = r.balanceDebit ?? 0;
      row[headers.balanceCredit ?? 'Dư Có'] = r.balanceCredit ?? 0;
    } else if (headers.balance) {
      row[headers.balance] = r.runningBalance;
    }
    if (headers.account) {
      row[headers.account] = r.accountCode?.trim() ?? '';
    }
    return row;
  });
  const sheet = XLSX.utils.json_to_sheet(data);
  const book = XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(book, sheet, 'SoCai');
  XLSX.writeFile(book, fileName);
}

export function formatLedgerExportFileName(accountCode: string): string {
  const stamp = new Date().toISOString().slice(0, 10);
  return `so-cai-${accountCode}-${stamp}.xlsx`;
}

/** Display helpers for Excel sheet (optional second export with formatted strings) */
export function ledgerRowsForDisplay(rows: LedgerEntryDto[]) {
  return rows.map(r => ({
    ...r,
    debitDisplay: formatVnd(r.debitAmount),
    creditDisplay: formatVnd(r.creditAmount),
    balanceDebitDisplay: formatVnd(r.balanceDebit ?? 0),
    balanceCreditDisplay: formatVnd(r.balanceCredit ?? 0),
    balanceDisplay: formatVnd(r.runningBalance),
  }));
}
