import type { LedgerEntryDto } from '../../services/kt/models';
import { formatDateLocal } from '../../utils/formatters';

export type LedgerBalancePoint = {
  label: string;
  /** Signed net — internal; chart line uses balanceDebit/balanceCredit. */
  balance: number;
  balanceDebit: number;
  balanceCredit: number;
  debit: number;
  credit: number;
};

export type LedgerDailyPoint = {
  label: string;
  debit: number;
  credit: number;
};

export type LedgerChartSummary = {
  totalDebit: number;
  totalCredit: number;
  /** Signed net cuối kỳ (parity BE). */
  closingBalance: number;
  closingBalanceDebit: number;
  closingBalanceCredit: number;
  entryCount: number;
};

export type LedgerDonutPoint = {
  name: string;
  value: number;
  fill: string;
};

export type LedgerChartData = {
  balanceSeries: LedgerBalancePoint[];
  dailySeries: LedgerDailyPoint[];
  donutSeries: LedgerDonutPoint[];
  summary: LedgerChartSummary;
};

const DONUT_COLORS = { debit: '#1677ff', credit: '#fa8c16' } as const;

/** Parity BE `AccountBalanceHelper.SplitBalance`. */
export function splitLedgerDisplayBalance(net: number): { debit: number; credit: number } {
  if (net >= 0) return { debit: net, credit: 0 };
  return { debit: 0, credit: -net };
}

function resolveEntrySplitBalance(row: LedgerEntryDto): { debit: number; credit: number } {
  if (row.balanceDebit != null || row.balanceCredit != null) {
    return { debit: row.balanceDebit ?? 0, credit: row.balanceCredit ?? 0 };
  }
  return splitLedgerDisplayBalance(row.runningBalance);
}

function detailRowsOnly(items: LedgerEntryDto[]): LedgerEntryDto[] {
  return items.filter(r => (r.rowTag ?? 0) === 0);
}

function resolveClosingSplit(items: LedgerEntryDto[]): { debit: number; credit: number; signed: number } {
  const periodTotal = [...items].reverse().find(r => r.rowTag === 2);
  const detailItems = detailRowsOnly(items);
  const lastDetail = detailItems.length > 0 ? detailItems[detailItems.length - 1] : undefined;
  const row = periodTotal ?? lastDetail;
  if (!row) return { debit: 0, credit: 0, signed: 0 };
  const split = resolveEntrySplitBalance(row);
  return { ...split, signed: row.runningBalance };
}

export function buildLedgerChartData(items: LedgerEntryDto[]): LedgerChartData {
  const detailItems = detailRowsOnly(items);

  const balanceSeries: LedgerBalancePoint[] = detailItems.map(r => {
    const split = resolveEntrySplitBalance(r);
    return {
      label: formatDateLocal(r.entryDate),
      balance: r.runningBalance,
      balanceDebit: split.debit,
      balanceCredit: split.credit,
      debit: r.debitAmount,
      credit: r.creditAmount,
    };
  });

  const dailyMap = new Map<string, { debit: number; credit: number }>();
  for (const r of detailItems) {
    const day = r.entryDate.slice(0, 10);
    const cur = dailyMap.get(day) ?? { debit: 0, credit: 0 };
    cur.debit += r.debitAmount;
    cur.credit += r.creditAmount;
    dailyMap.set(day, cur);
  }

  const dailySeries: LedgerDailyPoint[] = [...dailyMap.entries()]
    .sort(([a], [b]) => a.localeCompare(b))
    .map(([day, v]) => ({
      label: formatDateLocal(day),
      debit: v.debit,
      credit: v.credit,
    }));

  const totalDebit = detailItems.reduce((s, r) => s + r.debitAmount, 0);
  const totalCredit = detailItems.reduce((s, r) => s + r.creditAmount, 0);
  const closing = resolveClosingSplit(items);

  const donutSeries: LedgerDonutPoint[] = [
    { name: 'PS Nợ', value: totalDebit, fill: DONUT_COLORS.debit },
    { name: 'PS Có', value: totalCredit, fill: DONUT_COLORS.credit },
  ].filter(p => p.value > 0);

  return {
    balanceSeries,
    dailySeries,
    donutSeries,
    summary: {
      totalDebit,
      totalCredit,
      closingBalance: closing.signed,
      closingBalanceDebit: closing.debit,
      closingBalanceCredit: closing.credit,
      entryCount: detailItems.length,
    },
  };
}

export type NormalizedReportChartKind = 'line' | 'bar' | 'donut';

export function normalizeReportChartKind(kind: string): NormalizedReportChartKind | null {
  const k = kind.trim().toLowerCase();
  if (k === 'line') return 'line';
  if (k === 'bar') return 'bar';
  if (k === 'donut') return 'donut';
  return null;
}

/** Compact VND axis ticks (triệu / tỷ). */
export function formatChartVndAxis(value: number): string {
  const n = Number(value);
  if (!Number.isFinite(n)) return '0';
  const abs = Math.abs(n);
  if (abs >= 1_000_000_000) return `${(n / 1_000_000_000).toFixed(1)}B`;
  if (abs >= 1_000_000) return `${(n / 1_000_000).toFixed(0)}M`;
  if (abs >= 1_000) return `${(n / 1_000).toFixed(0)}K`;
  return String(Math.round(n));
}
